import React, { useState } from 'react';
import axios from 'axios';

/**
 * Test component to verify frontend-backend connection
 */
const TestConnection = () => {
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);

  const testBackendConnection = async () => {
    setLoading(true);
    setResult('Testing...');

    try {
      console.log('Testing backend connection...');
      const response = await axios.get('/health');
      console.log('Backend response:', response.data);
      setResult(`✅ Backend connected! Response: ${JSON.stringify(response.data, null, 2)}`);
    } catch (error) {
      console.error('Backend connection failed:', error);
      setResult(`❌ Backend connection failed: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  const testSignup = async () => {
    setLoading(true);
    setResult('Testing signup...');

    try {
      const testData = {
        name: 'Test User',
        email: `test${Date.now()}@example.com`,
        password: 'test123',
        role: 'patient'
      };

      console.log('Testing signup with:', testData);
      const response = await axios.post('/api/auth/signup', testData);
      console.log('Signup response:', response.data);
      setResult(`✅ Signup successful! Response: ${JSON.stringify(response.data, null, 2)}`);
    } catch (error) {
      console.error('Signup failed:', error);
      setResult(`❌ Signup failed: ${error.response?.data?.message || error.message}`);
    } finally {
      setLoading(false);
    }
  };

  const testLogin = async () => {
    setLoading(true);
    setResult('Testing login...');

    try {
      const loginData = {
        email: 'test@example.com',
        password: 'test123'
      };

      console.log('Testing login with:', loginData);
      const response = await axios.post('/api/auth/login', loginData);
      console.log('Login response:', response.data);
      setResult(`✅ Login successful! Response: ${JSON.stringify(response.data, null, 2)}`);
    } catch (error) {
      console.error('Login failed:', error);
      setResult(`❌ Login failed: ${error.response?.data?.message || error.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ 
      position: 'fixed', 
      bottom: '10px', 
      left: '10px', 
      background: 'white', 
      border: '1px solid #ccc', 
      padding: '15px', 
      borderRadius: '5px',
      fontSize: '12px',
      zIndex: 9999,
      maxWidth: '400px',
      maxHeight: '300px',
      overflow: 'auto'
    }}>
      <h4>Connection Test</h4>
      <div style={{ marginBottom: '10px' }}>
        <button onClick={testBackendConnection} disabled={loading} style={{ marginRight: '5px' }}>
          Test Backend
        </button>
        <button onClick={testSignup} disabled={loading} style={{ marginRight: '5px' }}>
          Test Signup
        </button>
        <button onClick={testLogin} disabled={loading}>
          Test Login
        </button>
      </div>
      <div style={{ 
        background: '#f5f5f5', 
        padding: '10px', 
        borderRadius: '3px',
        whiteSpace: 'pre-wrap',
        fontSize: '10px'
      }}>
        {result}
      </div>
    </div>
  );
};

export default TestConnection;
